question:
Какой результат обычно выведет программа на ASCII-совместимой системе?

char c = 'A';
std::cout << static_cast<int>(c);

Что произойдёт в следующем коде?

char c = 'A';
c = c + 1;
std::cout << c;

Какой результат выведет код?

bool a = -10;
bool b = 0;
std::cout << a << " " << b;

Какой результат получит переменная result?

int a = 5;
int b = 2;
double result = a / b;

Какой результат даст код?

double x = -3.9;
int y = static_cast<int>(x);

Какой тип обычно получит переменная result?

short a = 10;
short b = 20;
auto result = a + b;

Какой тип будет у result?

int a = 5;
double b = 2.5;
auto result = a + b;

Какой результат даст код?

unsigned int x = 0;
--x;

Почему следующий код может дать неправильный результат?

int a = 100000;
int b = 100000;
long long result = a * b;

Какие варианты безопасно заставляют умножение выполняться как long long?

int a = 100000;
int b = 100000;

Какой результат обычно выведет код при 32-битных int и unsigned int?

int x = -1;
unsigned int y = 1;
std::cout << (x < y);

Почему следующий цикл является ошибочным?

for (unsigned int i = 10; i >= 0; --i) {
    std::cout << i;
}

Какие типы выведет компилятор для переменных?

auto a = 10;
auto b = 10u;
auto c = 10LL;
auto d = 3.14f;

Что произойдёт в коде?

auto x = 10;
x = 3.9;
std::cout << x;
